package com.csj.archive.logistics.runtime;
import org.springframework.scheduling.annotation.Scheduled; import org.springframework.stereotype.Component; import java.util.concurrent.atomic.AtomicBoolean;
@Component public class ArchiveOsRuntimeDeliveryScheduler { private final ArchiveOsRuntimeDeliveryService service; private final ArchiveOsRuntimeProperties properties; private final AtomicBoolean running=new AtomicBoolean(); public ArchiveOsRuntimeDeliveryScheduler(ArchiveOsRuntimeDeliveryService service,ArchiveOsRuntimeProperties properties){this.service=service;this.properties=properties;} @Scheduled(initialDelayString="${ARCHIVEOS_RUNTIME_INGEST_STARTUP_DELAY_MS:60000}",fixedDelayString="${ARCHIVEOS_RUNTIME_INGEST_FIXED_DELAY_MS:30000}") public void publish(){if(!properties.isSchedulerEnabled()||!running.compareAndSet(false,true))return;try{service.recoverStalePublishing();service.publishBatch();}finally{running.set(false);}} }
